// Parser del resumen MENSUAL para DOCX con DocxTemplater
const item = $input.first();
const contenido = String(item.json.contenido || '').replace(/\r/g, '');
const inicio = String(item.json.periodo_inicio || '');

// ---- 1) Periodo legible: "Junio de 2026" ----
const meses = ['enero','febrero','marzo','abril','mayo','junio',
               'julio','agosto','septiembre','octubre','noviembre','diciembre'];
function mesAnio(fecha) {
  const d = new Date(new Date(fecha).getTime() + 2 * 60 * 60 * 1000);
  const m = meses[d.getUTCMonth()];
  return m.charAt(0).toUpperCase() + m.slice(1) + ' de ' + d.getUTCFullYear();
}
const periodo = inicio ? mesAnio(inicio) : '';

// ---- 2) Trocear por las 4 secciones del MENSUAL ----
const TITULOS = ['ESTADO DEL MES', 'EVOLUCION Y PATRONES', 'DECISIONES CLAVE DEL MES', 'PRIORIDADES DEL MES SIGUIENTE'];
function norm(s){ return s.replace(/Ó/g,'O').replace(/Á/g,'A').replace(/É/g,'E').replace(/Í/g,'I').replace(/Ú/g,'U'); }
const contNorm = norm(contenido);
function seccionesPorIndice(texto, textoNorm) {
  const idx = TITULOS.map(t => ({ t, i: textoNorm.indexOf(t) })).filter(o => o.i !== -1);
  const out = {};
  for (let k = 0; k < idx.length; k++) {
    const ini = idx[k].i + idx[k].t.length;
    const finSec = (k + 1 < idx.length) ? idx[k + 1].i : texto.length;
    out[idx[k].t] = texto.slice(ini, finSec).trim();
  }
  return out;
}
const secs = seccionesPorIndice(contenido, contNorm);

const estado_mes  = secs['ESTADO DEL MES'] || '';
const evolucion   = secs['EVOLUCION Y PATRONES'] || '';
const decisiones  = secs['DECISIONES CLAVE DEL MES'] || '';
const prioridades = secs['PRIORIDADES DEL MES SIGUIENTE'] || '';

function separarSubapartados(bloque) {
  const reID = /^I\+D[^\n:]*:\s*$/m;
  const reCom = /^Comercial[^\n:]*:\s*$/m;
  const idMatch = bloque.match(reID);
  const comMatch = bloque.match(reCom);
  let id = '', comercial = '';
  if (idMatch && comMatch) {
    const iID = bloque.indexOf(idMatch[0]);
    const iCom = bloque.indexOf(comMatch[0]);
    if (iID < iCom) {
      id = bloque.slice(iID + idMatch[0].length, iCom).trim();
      comercial = bloque.slice(iCom + comMatch[0].length).trim();
    } else {
      comercial = bloque.slice(iCom + comMatch[0].length, iID).trim();
      id = bloque.slice(iID + idMatch[0].length).trim();
    }
  } else if (idMatch) {
    id = bloque.slice(bloque.indexOf(idMatch[0]) + idMatch[0].length).trim();
  } else if (comMatch) {
    comercial = bloque.slice(bloque.indexOf(comMatch[0]) + comMatch[0].length).trim();
  } else {
    id = bloque.trim();
  }
  return { id, comercial };
}

const evoSub = separarSubapartados(evolucion);
const decSub = separarSubapartados(decisiones);

function separarPrioridades(bloque) {
  const lineas = bloque.split(/\n/).map(l => l.trim()).filter(l => l.startsWith('- '));
  let id = [], comercial = [];
  for (let l of lineas) {
    const mDep = l.match(/\|\s*Departamento:\s*(.+?)\s*$/i);
    const dep = mDep ? mDep[1].trim() : 'Comercial';
    let texto = l.replace(/\s*\|\s*Departamento:\s*.+$/i, '').trim();
    texto = texto.replace(/^- \[?/, '- ').replace(/\]$/, '');
    if (/I\+?D/i.test(dep)) id.push(texto); else comercial.push(texto);
  }
  return { id: id.join('\n'), comercial: comercial.join('\n') };
}
const priSub = separarPrioridades(prioridades);

function jsonSafe(s) {
  return String(s || '').replace(/\\/g, '\\\\').replace(/"/g, '\\"');
}

return [{
  json: {
    ...item.json,
    periodo,
    estado_mes: jsonSafe(estado_mes),
    evolucion_id: jsonSafe(evoSub.id),
    evolucion_comercial: jsonSafe(evoSub.comercial),
    decisiones_id: jsonSafe(decSub.id),
    decisiones_comercial: jsonSafe(decSub.comercial),
    prioridades_id: jsonSafe(priSub.id),
    prioridades_comercial: jsonSafe(priSub.comercial)
  }
}];
